```

## 代码示例

### 待办小应用 code

```javascript
// 添加待办
mcpServer.tool({
  name: 'add_todo',
  description: '添加待办事项',
  parameters: z.object({
    title: z.string().describe('待办标题'),
    priority: z.enum(['high', 'medium', 'low']).optional()
  }),
  execute: async ({ title, priority = 'medium' }) => {
    const todos = await storage.get('todos') || [];
    const newTodo = {
      id: Date.now().toString(),
      title,
      priority,
      done: false,
      createdAt: new Date().toISOString()
    };
    todos.push(newTodo);
    await storage.set('todos', todos);
    return { success: true, todo: newTodo };
  }
});

// 列出待办
mcpServer.tool({
  name: 'list_todos',
  description: '列出所有待办事项',
  parameters: z.object({
    filter: z.enum(['all', 'done', 'pending']).optional()
  }),
  execute: async ({ filter = 'all' }) => {
    const todos = await storage.get('todos') || [];
    if (filter === 'done') return todos.filter(t => t.done);
    if (filter === 'pending') return todos.filter(t => !t.done);
    return todos;
  }
});
```

